      CREATE INDEX IF NOT EXISTS idx_recruiter_feedback_candidate ON recruiter_feedback(candidate_id);
      CREATE INDEX IF NOT EXISTS idx_recruiter_feedback_recruiter ON recruiter_feedback(recruiter_id);
    `);

    // ============================================================
