        thisWeek: parseInt(interviews.this_week || 0),
        practiceSessions: parseInt(practiceCount.total || 0),
        mockSessions: parseInt(mockCount.total || 0),
      },
      onboarding: {
        totalSessions: parseInt(onboardingData.total || 0),
